56	function computeClaim(step: ClaimStep, scenario: Scenario): { payout: number; remainingCap: number } {
57	  const policyStep = scenario.steps[step.policy] as QuoteStep;
58	  const insuranceSum = (BASE_PREMIUM[policyStep.items[0].type] ?? 0) * INSURANCE_VALUE_MULTIPLIER;
59	  const cap = insuranceSum * CAP_MULTIPLIER;
60	  const damageAmount = step.incident.damages[0].amount;
61	  const damagedItem = policyStep.items[0];
62	  const reducedDamage = (damagedItem.enchantment ?? 0) >= 8 ? damageAmount * 0.5 : damageAmount;
63	  const payout = reducedDamage - CLAIM_DEDUCTIBLE;
64	  const remainingCap = cap - payout;
65	  return { payout, remainingCap };
66	}
