68	function computeBasePremium(items: Item[]): number {
69	  const countsByType: Record<string, number> = {};
70	  for (const item of items) {
71	    countsByType[item.type] = (countsByType[item.type] ?? 0) + 1;
72	  }
73	  let basePremium = 0;
74	  for (const [type, count] of Object.entries(countsByType)) {
75	    if (COMPONENT_TYPES.has(type) && count === COMPONENT_BLOCK_SIZE) {
76	      basePremium += COMPONENT_BLOCK_PRICE;
77	    } else {
78	      const perItem = BASE_PREMIUM[type] ?? 0;
79	      basePremium += perItem * count;
80	    }
81	  }
82	  return basePremium;
83	}
