85	function computeItemSurcharges(items: Item[]): number {
86	  let surcharges = 0;
87	  for (const item of items) {
88	    const itemBase = BASE_PREMIUM[item.type] ?? 0;
89	    if (item.cursed) {
90	      surcharges += itemBase * CURSED_SURCHARGE_RATE;
91	    }
92	    if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) {
93	      surcharges += itemBase * HIGH_ENCHANTMENT_RATE;
94	    }
95	  }
96	  return surcharges;
97	}
