99	function computeQuote(
100	  step: QuoteStep,
101	  stepIndex: number,
102	  customer: Customer,
103	): { premium: number } {
104	  const basePremium = computeBasePremium(step.items);
105	  const itemSurcharges = computeItemSurcharges(step.items);
106	  const firstInsurance = basePremium * FIRST_INSURANCE_RATE;
107	  const loyaltyDiscount =
108	    customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD
109	      ? basePremium * LOYALTY_DISCOUNT_RATE
110	      : 0;
111	  const isFollowUpQuote = stepIndex >= 1;
112	  const followUpDiscount = isFollowUpQuote ? basePremium * FOLLOW_UP_DISCOUNT_RATE : 0;
113	  const rawPremium = basePremium + itemSurcharges + firstInsurance - loyaltyDiscount - followUpDiscount + PROCESSING_FEE;
114	  const premium = Math.ceil(rawPremium);
115	  return { premium };
116	}
